svg.script:
(function(){
  var svg = document.currentScript.closest('svg');
  if (!svg) return;
  var targets = svg.querySelectorAll('[id*="_tr"], #eeacmOkDAsw20');
  var shouldStop = false;

  function pauseTargets() {
    targets.forEach(function(el) {
      el.style.animationPlayState = 'paused';
    });
  }

  // Pause initially unless loaded via #splash (splash screen context)
  if (window.location.hash !== '#splash') pauseTargets();
  // Listen for iteration end on first target
  var mainEl = targets[0];
  if (mainEl) {
    mainEl.addEventListener('animationiteration', function() {
      if (shouldStop) {
        shouldStop = false;
        pauseTargets();
      }
    });
  }

  svg.addEventListener('mouseenter', function() {
    shouldStop = false;
    targets.forEach(function(el) {
      el.style.animationPlayState = 'running';
    });
  });

  svg.addEventListener('mouseleave', function() {
    shouldStop = true;
  });
})();
